1	const BASE_PRICES: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	};
8	
9	const FIRST_INSURANCE_SURCHARGE_NUM = 11;
10	const FIRST_INSURANCE_SURCHARGE_DEN = 10;
11	const FIXED_FEE = 5;
12	
13	function quotePremium(item: { type: string }): number {
14	  const basePrice = BASE_PRICES[item.type];
15	  const surcharged = Math.ceil(
16	    (basePrice * FIRST_INSURANCE_SURCHARGE_NUM) / FIRST_INSURANCE_SURCHARGE_DEN
17	  );
18	  return surcharged + FIXED_FEE;
19	}
20	
21	export function runScenario(scenario: any): unknown {
22	  const item = scenario.steps[0].items[0];
23	  const premium = quotePremium(item);
24	  return { results: [{ premium }] };
25	}
